rules.pseudocode:
# Mask infeasible actions: if no food at position, set Q[z, 'eat'] = -infinity
for each action a in actions:
    if a == 'eat' and not food_at_position:
        q_values[a] = -infinity
    else:
        q_values[a] = Q[z, a]
# Softmax
max_q = max(q_values.values() that are not -inf)
probs = {}
for a in actions:
    if q_values[a] == -infinity:
        probs[a] = 0
    else:
        probs[a] = exp(beta * (q_values[a] - max_q))
total = sum(probs.values())
probs = {a: p / total for a, p in probs.items()}
selected_action = sample from probs
